// Iterative approach
public TreeNode insert(TreeNode root, int val) {
    TreeNode newNode = new TreeNode(val);
    if (root == null) return newNode;
    TreeNode curr = root;
    while (true) {
        if (val < curr.val) {
            if (curr.left == null) { curr.left = newNode; break; }
            curr = curr.left;
        } else {
            if (curr.right == null) { curr.right = newNode; break; }
            curr = curr.right;
        }
    }
    return root;
}

